const express = require('express');
const multer = require('multer');
const path = require('path');
const fs = require('fs');
const crypto = require('crypto');

// Configuration constants
const UPLOAD_DIR = path.resolve(__dirname, 'uploads');
const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5 MB
const MAX_FILES_PER_REQUEST = 5;

// Allowed MIME types and their corresponding extensions
const ALLOWED_TYPES = {
  'image/jpeg': ['.jpg', '.jpeg'],
  'image/png': ['.png'],
  'image/gif': ['.gif'],
  'image/webp': ['.webp'],
  'application/pdf': ['.pdf'],
  'text/plain': ['.txt'],
  'text/csv': ['.csv'],
};

// Magic bytes for file type validation
const MAGIC_BYTES = {
  'image/jpeg': [Buffer.from([0xff, 0xd8, 0xff])],
  'image/png': [Buffer.from([0x89, 0x50, 0x4e, 0x47])],
  'image/gif': [Buffer.from('GIF87a'), Buffer.from('GIF89a')],
  'image/webp': [Buffer.from('RIFF')],
  'application/pdf': [Buffer.from('%PDF')],
};

// Ensure upload directory exists
function ensureUploadDir() {
  if (!fs.existsSync(UPLOAD_DIR)) {
    fs.mkdirSync(UPLOAD_DIR, { recursive: true, mode: 0o750 });
  }
}

// Generate a safe, unique filename
function generateSafeFilename(originalName) {
  const ext = path.extname(originalName).toLowerCase();
  const uniqueId = crypto.randomBytes(16).toString('hex');
  const timestamp = Date.now();
  return `${timestamp}-${uniqueId}${ext}`;
}

// Validate file extension against allowed types
function isAllowedExtension(filename) {
  const ext = path.extname(filename).toLowerCase();
  return Object.values(ALLOWED_TYPES).flat().includes(ext);
}

// Validate MIME type
function isAllowedMimeType(mimetype) {
  return Object.keys(ALLOWED_TYPES).includes(mimetype);
}

// Validate that the file extension matches the MIME type
function extensionMatchesMimeType(filename, mimetype) {
  const ext = path.extname(filename).toLowerCase();
  const allowedExtensions = ALLOWED_TYPES[mimetype];
  if (!allowedExtensions) return false;
  return allowedExtensions.includes(ext);
}

// Validate file content by checking magic bytes
function validateMagicBytes(buffer, declaredMimeType) {
  const signatures = MAGIC_BYTES[declaredMimeType];

  // For types without magic byte checks (e.g., text/plain, text/csv), skip
  if (!signatures) {
    // For text types, ensure the buffer doesn't contain null bytes (binary content)
    if (declaredMimeType.startsWith('text/')) {
      return !buffer.includes(0x00);
    }
    return true;
  }

  return signatures.some((sig) => {
    if (buffer.length < sig.length) return false;
    const fileHeader = buffer.slice(0, sig.length);
    return fileHeader.equals(sig);
  });
}

// Sanitize the original filename to prevent path traversal
function sanitizeFilename(filename) {
  // Remove path components, keep only the base name
  let sanitized = path.basename(filename);
  // Remove any null bytes
  sanitized = sanitized.replace(/\0/g, '');
  // Remove any directory traversal characters
  sanitized = sanitized.replace(/\.\./g, '');
  // Remove any non-alphanumeric characters except dots, hyphens, underscores
  sanitized = sanitized.replace(/[^a-zA-Z0-9.\-_]/g, '_');
  return sanitized;
}

// Configure multer storage
const storage = multer.diskStorage({
  destination: function (req, file, cb) {
    ensureUploadDir();

    // Validate that the resolved path is within UPLOAD_DIR
    const resolvedPath = path.resolve(UPLOAD_DIR);
    if (!resolvedPath.startsWith(path.resolve(__dirname))) {
      return cb(new Error('Invalid upload directory configuration'));
    }

    cb(null, UPLOAD_DIR);
  },
  filename: function (req, file, cb) {
    const sanitizedOriginal = sanitizeFilename(file.originalname);
    const safeFilename = generateSafeFilename(sanitizedOriginal);
    cb(null, safeFilename);
  },
});

// Multer file filter
const fileFilter = function (req, file, cb) {
  // Check MIME type
  if (!isAllowedMimeType(file.mimetype)) {
    return cb(
      new Error(
        `File type '${file.mimetype}' is not allowed. Allowed types: ${Object.keys(ALLOWED_TYPES).join(', ')}`
      ),
      false
    );
  }

  // Check extension
  const sanitizedName = sanitizeFilename(file.originalname);
  if (!isAllowedExtension(sanitizedName)) {
    return cb(
      new Error(
        `File extension is not allowed. Allowed extensions: ${Object.values(ALLOWED_TYPES).flat().join(', ')}`
      ),
      false
    );
  }

  // Check extension matches MIME type
  if (!extensionMatchesMimeType(sanitizedName, file.mimetype)) {
    return cb(
      new Error('File extension does not match the declared MIME type'),
      false
    );
  }

  cb(null, true);
};

// Create multer upload instance
const upload = multer({
  storage: storage,
  fileFilter: fileFilter,
  limits: {
    fileSize: MAX_FILE_SIZE,
    files: MAX_FILES_PER_REQUEST,
    fields: 10,
    fieldNameSize: 100,
    fieldSize: 1024,
  },
});

// Post-upload validation middleware (validates magic bytes of saved files)
async function postUploadValidation(req, res, next) {
  if (!req.files && !req.file) {
    return next();
  }

  const files = req.files || (req.file ? [req.file] : []);
  const invalidFiles = [];

  for (const file of files) {
    try {
      const filePath = path.resolve(file.path);

      // Ensure the file is within the upload directory
      if (!filePath.startsWith(path.resolve(UPLOAD_DIR))) {
        invalidFiles.push({
          file: file.originalname,
          reason: 'File stored outside allowed directory',
          path: file.path,
        });
        continue;
      }

      // Read the first 16 bytes for magic byte validation
      const fd = fs.openSync(filePath, 'r');
      const headerBuffer = Buffer.alloc(16);
      fs.readSync(fd, headerBuffer, 0, 16, 0);
      fs.closeSync(fd);

      if (!validateMagicBytes(headerBuffer, file.mimetype)) {
        invalidFiles.push({
          file: file.originalname,
          reason: 'File content does not match declared MIME type',
          path: file.path,
        });
      }
    } catch (err) {
      invalidFiles.push({
        file: file.originalname,
        reason: `Validation error: ${err.message}`,
        path: file.path,
      });
    }
  }

  // Remove invalid files from disk
  for (const invalid of invalidFiles) {
    try {
      if (fs.existsSync(invalid.path)) {
        fs.unlinkSync(invalid.path);
      }
    } catch (err) {
      console.error(`Failed to remove invalid file ${invalid.path}:`, err.message);
    }
  }

  if (invalidFiles.length > 0) {
    // Also remove any valid files if some were invalid (atomic behavior)
    for (const file of files) {
      const isInvalid = invalidFiles.some((inv) => inv.path === file.path);
      if (!isInvalid) {
        try {
          if (fs.existsSync(file.path)) {
            fs.unlinkSync(file.path);
          }
        } catch (err) {
          console.error(`Failed to clean up file ${file.path}:`, err.message);
        }
      }
    }

    return res.status(400).json({
      success: false,
      error: 'File validation failed',
      details: invalidFiles.map((f) => ({
        file: f.file,
        reason: f.reason,
      })),
    });
  }

  next();
}

// Error handling middleware for multer errors
function handleUploadError(err, req, res, next) {
  // Clean up any uploaded files on error
  const files = req.files || (req.file ? [req.file] : []);
  for (const file of files) {
    try {
      if (file.path && fs.existsSync(file.path)) {
        fs.unlinkSync(file.path);
      }
    } catch (cleanupErr) {
      console.error(`Failed to clean up file on error: ${cleanupErr.message}`);
    }
  }

  if (err instanceof multer.MulterError) {
    const messages = {
      LIMIT_FILE_SIZE: `File too large. Maximum size is ${MAX_FILE_SIZE / (1024 * 1024)} MB`,
      LIMIT_FILE_COUNT: `Too many files. Maximum is ${MAX_FILES_PER_REQUEST} files per request`,
      LIMIT_UNEXPECTED_FILE: 'Unexpected file field',
      LIMIT_FIELD_KEY: 'Field name too long',
      LIMIT_FIELD_VALUE: 'Field value too long',
      LIMIT_FIELD_COUNT: 'Too many fields',
      LIMIT_PART_COUNT: 'Too many parts',
    };

    return res.status(400).json({
      success: false,
      error: messages[err.code] || err.message,
    });
  }

  if (err) {
    return res.status(400).json({
      success: false,
      error: err.message,
    });
  }

  next();
}

// ---- Express App Setup ----

const app = express();

// Single file upload endpoint
app.post(
  '/api/upload',
  (req, res, next) => {
    upload.single('file')(req, res, (err) => {
      if (err) return handleUploadError(err, req, res, next);
      next();
    });
  },
  postUploadValidation,
  (req, res) => {
    if (!req.file) {
      return res.status(400).json({
        success: false,
        error: 'No file provided',
      });
    }

    res.status(200).json({
      success: true,
      message: 'File uploaded successfully',
      file: {
        originalName: sanitizeFilename(req.file.originalname),
        storedName: req.file.filename,
        size: req.file.size,
        mimeType: req.file.mimetype,
      },
    });
  }
);

// Multiple files upload endpoint
app.post(
  '/api/upload/multiple',
  (req, res, next) => {
    upload.array('files', MAX_FILES_PER_REQUEST)(req, res, (err) => {
      if (err) return handleUploadError(err, req, res, next);
      next();
    });
  },
  postUploadValidation,
  (req, res) => {
    if (!req.files || req.files.length === 0) {
      return res.status(400).json({
        success: false,
        error: 'No files provided',
      });
    }

    const uploadedFiles = req.files.map((file) => ({
      originalName: sanitizeFilename(file.originalname),
      storedName: file.filename,
      size: file.size,
      mimeType: file.mimetype,
    }));

    res.status(200).json({
      success: true,
      message: `${uploadedFiles.length} file(s) uploaded successfully`,
      files: uploadedFiles,
    });
  }
);

// Health check
app.get('/api/upload/config', (req, res) => {
  res.json({
    maxFileSize: MAX_FILE_SIZE,
    maxFilesPerRequest: MAX_FILES_PER_REQUEST,
    allowedTypes: Object.keys(ALLOWED_TYPES),
    allowedExtensions: [...new Set(Object.values(ALLOWED_TYPES).flat())],
  });
});

// Start server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  ensureUploadDir();
  console.log(`File upload server running on port ${PORT}`);
  console.log(`Upload directory: ${UPLOAD_DIR}`);
  console.log(`Max file size: ${MAX_FILE_SIZE / (1024 * 1024)} MB`);
  console.log(`Max files per request: ${MAX_FILES_PER_REQUEST}`);
  console.log(`Allowed types: ${Object.keys(ALLOWED_TYPES).join(', ')}`);
});

module.exports = {
  app,
  upload,
  postUploadValidation,
  handleUploadError,
  sanitizeFilename,
  generateSafeFilename,
  validateMagicBytes,
  isAllowedExtension,
  isAllowedMimeType,
  extensionMatchesMimeType,
  UPLOAD_DIR,
  MAX_FILE_SIZE,
  MAX_FILES_PER_REQUEST,
  ALLOWED_TYPES,
};